const ethers = require('ethers');
const express = require('express');
const app = express();
app.use(express.json());

// Secure configuration
const config = {
  rpcUrl: process.env.RPC_URL,
  privateKey: process.env.PRIVATE_KEY,
  gasLimit: 21000,
  gasPriceMultiplier: 1.2
};

// Validate configuration
if (!config.rpcUrl || !config.privateKey) {
  throw new Error('Missing required configuration');
}

// Create provider and wallet
const provider = new ethers.providers.JsonRpcProvider(config.rpcUrl);
const wallet = new ethers.Wallet(config.privateKey, provider);

// Secure input validation
const validateAddress = (address) => {
  if (!address || !ethers.utils.isAddress(address)) {
    throw new Error('Invalid address');
  }
  return address;
};

const validateAmount = (amount) => {
  if (!amount || isNaN(amount) || parseFloat(amount) <= 0) {
    throw new Error('Invalid amount');
  }
  return ethers.utils.parseEther(amount.toString());
};

// Secure transaction functions
const sendETH = async (toAddress, amount) => {
  try {
    const validatedAddress = validateAddress(toAddress);
    const validatedAmount = validateAmount(amount);
    
    const tx = {
      to: validatedAddress,
      value: validatedAmount,
      gasLimit: config.gasLimit,
      gasPrice: await provider.getGasPrice()
    };

    const signedTx = await wallet.signTransaction(tx);
    const receipt = await provider.sendTransaction(signedTx);
    
    return {
      success: true,
      transactionHash: receipt.hash,
      receipt: receipt
    };
  } catch (error) {
    throw new Error(`Transaction failed: ${error.message}`);
  }
};

const interactWithContract = async (contractAddress, abi, functionName, args = [], value = 0) => {
  try {
    const contract = new ethers.Contract(contractAddress, abi, wallet);
    const tx = await contract[functionName](...args, { value: ethers.utils.parseEther(value.toString()) });
    const receipt = await tx.wait();
    
    return {
      success: true,
      transactionHash: receipt.transactionHash,
      receipt: receipt
    };
  } catch (error) {
    throw new Error(`Contract interaction failed: ${error.message}`);
  }
};

// API endpoints
app.post('/send-eth', async (req, res) => {
  try {
    const { to, amount } = req.body;
    const result = await sendETH(to, amount);
    res.json(result);
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

app.post('/contract-call', async (req, res) => {
  try {
    const { contractAddress, abi, functionName, args, value } = req.body;
    const result = await interactWithContract(contractAddress, abi, functionName, args, value);
    res.json(result);
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

// Health check
app.get('/health', (req, res) => {
  res.json({ status: 'healthy' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = {
  sendETH,
  interactWithContract
};